assignments.value:
={{ (() => {
  const caption = ($('SalesIQ - Intro').first().json.body.message?.meta?.comments?.[$('Split attachments').item.json.id] || '').toString().trim();
  const PREFIX = 'Here is my attachment description: ';
  const marker = '[File type not supported]';
  return caption ? (caption + '\n' + PREFIX + marker) : (PREFIX + marker);
})() }}

={{ (() => {
  const caption = ($('SalesIQ - Intro').first().json.body.message?.meta?.comments?.[$('Split attachments').item.json.id] || '').toString().trim();
  const pdfText = ($('Extract from File').item.json?.text || '').toString().trim();
  const PREFIX = 'Here is my attachment description: ';
  if (caption && pdfText) return caption + '\n' + PREFIX + pdfText;
  return pdfText ? PREFIX + pdfText : caption;
})() }}

={{ (() => {
  const caption = ($('SalesIQ - Intro').first().json.body.message?.meta?.comments?.[$('Split attachments').item.json.id] || '').toString().trim();
  const aiOut = $('Analyze image').item.json;
  let description = '';
  if (typeof aiOut?.content === 'string') {
    description = aiOut.content;
  } else if (Array.isArray(aiOut) && aiOut[0]?.content?.[0]?.text) {
    description = aiOut[0].content[0].text;
  } else if (typeof aiOut?.output_text === 'string') {
    description = aiOut.output_text;
  } else if (Array.isArray(aiOut?.output) && aiOut.output[0]?.content?.[0]?.text) {
    description = aiOut.output[0].content[0].text;
  }
  description = (description || '').toString().trim();
  const PREFIX = 'Here is my attachment description: ';
  if (caption && description) return caption + '\n' + PREFIX + description;
  return description ? PREFIX + description : (caption || 'See image description');
})() }}

