parameters.jsCode:
const u = String($('SalesIQ - Intro').first().json?.body?.visitor?.landing_page_url ?? '');
let entry_point = 'default';
if (/\/checkout/i.test(u)) entry_point = 'checkout';
else if (/[?&]utm_source=(google|bing)\b/i.test(u)) entry_point = 'paid_search';
else if (/^https?:\/\/[^/]+\/?([a-z]{2}(-[a-z]{2})?\/?)?(\?|#|$)/i.test(u)) entry_point = 'home';
return [{ json: { entry_point } }];
